member.example:
var rng = Enumerable.Range(0, 10).Do(x => Console.WriteLine(x)).Memoize();
var e1 = rng.GetEnumerator();
Assert.IsTrue(e1.MoveNext());    // 输出 0
Assert.AreEqual(0, e1.Current);
Assert.IsTrue(e1.MoveNext());    // 输出 1
Assert.AreEqual(1, e1.Current);
var e2 = rng.GetEnumerator();
Assert.IsTrue(e2.MoveNext());    // 不打印任何内容；Do的副作用
Assert.AreEqual(0, e2.Current);  // 已在e1迭代期间发生。
Assert.IsTrue(e1.MoveNext());    // 输出 2
Assert.AreEqual(2, e1.Current);

var rng = Enumerable.Range(0, 10).Publish();
var e1 = rng.GetEnumerator();    // e1 从元素 0 开始拥有源序列的视图
Assert.IsTrue(e1.MoveNext());
Assert.AreEqual(0, e1.Current);
Assert.IsTrue(e1.MoveNext());
Assert.AreEqual(1, e1.Current);
var e2 = rng.GetEnumerator();
Assert.IsTrue(e2.MoveNext());    // e2 从元素 2 开始拥有源序列的视图
Assert.AreEqual(2, e2.Current);
Assert.IsTrue(e1.MoveNext());    // e1 继续在其视图上进行枚举
Assert.AreEqual(2, e1.Current);

var rng = Enumerable.Range(0, 10).Share();
var e1 = rng.GetEnumerator();    // e1和e2都将消耗元素
var e2 = rng.GetEnumerator();    // 从源序列。
Assert.IsTrue(e1.MoveNext());
Assert.AreEqual(0, e1.Current);
Assert.IsTrue(e1.MoveNext());
Assert.AreEqual(1, e1.Current);
Assert.IsTrue(e2.MoveNext());    // e2 “窃取”元素 2
Assert.AreEqual(2, e2.Current);
Assert.IsTrue(e1.MoveNext());    // e1 看不到元素 2
Assert.AreEqual(3, e1.Current);
